{
  "journeyCode": "loan-approval",
  "name": "Loan Approval Journey with Conditions",
  "version": 1,
  "states": [
    {
      "name": "START",
      "type": "INITIAL"
    },
    {
      "name": "DOCUMENTS_PENDING",
      "type": "INTERMEDIATE"
    },
    {
      "name": "DOCUMENTS_VERIFIED",
      "type": "INTERMEDIATE"
    },
    {
      "name": "MANUAL_REVIEW",
      "type": "INTERMEDIATE"
    },
    {
      "name": "APPROVED",
      "type": "INTERMEDIATE"
    },
    {
      "name": "REJECTED",
      "type": "INTERMEDIATE"
    },
    {
      "name": "COMPLETED",
      "type": "FINAL"
    }
  ],
  "transitions": [
    {
      "source": "START",
      "event": "SUBMIT_APPLICATION",
      "target": "DOCUMENTS_PENDING"
    },
    {
      "source": "DOCUMENTS_PENDING",
      "event": "UPLOAD_DOCUMENTS",
      "target": "DOCUMENTS_VERIFIED"
    },
    {
      "source": "DOCUMENTS_VERIFIED",
      "event": "EVALUATE_RISK",
      "target": "APPROVED",
      "condition": "#eventData.riskScore <= 50 AND #eventData.income > 3000"
    },
    {
      "source": "DOCUMENTS_VERIFIED",
      "event": "EVALUATE_RISK",
      "target": "MANUAL_REVIEW",
      "condition": "#eventData.riskScore > 50 AND #eventData.riskScore <= 80"
    },
    {
      "source": "DOCUMENTS_VERIFIED",
      "event": "EVALUATE_RISK",
      "target": "REJECTED",
      "condition": "#eventData.riskScore > 80 OR #eventData.income <= 3000"
    },
    {
      "source": "MANUAL_REVIEW",
      "event": "MANUAL_APPROVAL",
      "target": "APPROVED"
    },
    {
      "source": "MANUAL_REVIEW",
      "event": "MANUAL_REJECTION",
      "target": "REJECTED"
    },
    {
      "source": "APPROVED",
      "event": "DISBURSE_LOAN",
      "target": "COMPLETED"
    },
    {
      "source": "REJECTED",
      "event": "NOTIFY_REJECTION",
      "target": "COMPLETED"
    }
  ]
}
